+
+impl TracePoset {
+    /// Build the dependency DAG induced by the trace's independence relation.
+    ///
+    /// For every `i < j`, we add an edge `i -> j` iff `NOT independent(e_i, e_j)`.
+    #[must_use]
+    pub fn from_trace(trace: &[TraceEvent]) -> Self {
